function string.ltrim(input)
    return string.gsub(input, "^[ \t\n\r]+", "")
end

function string.rtrim(input)
    return string.gsub(input, "[ \t\n\r]+$", "")
end

function string.trim(input)
    input = string.gsub(input, "^[ \t\n\r]+", "")
    return string.gsub(input, "[ \t\n\r]+$", "")
end

function string.lastselection(input)
    if not input then return input end
    local first, last = string.match(input,"(.*)/(.+)")
    return last or input, first
end

local function urlencodechar(char)
    return "%" .. string.format("%02X", string.byte(char))
end

function string.urlencode(input)
    -- convert line endings
    input = string.gsub(tostring(input), "\n", "\r\n")
    -- escape all characters but alphanumeric, '.' and '-'
    input = string.gsub(input, "([^%w%.%- ])", urlencodechar)
    -- convert spaces to "+" symbols
    return string.gsub(input, " ", "+")
end

local function urldecodehex(hex)
    return string.char(tonumber(hex, 16))
end

function string.urldecode(input)
    -- Replace '+' with space (URL encoding convention)
    input = string.gsub(input, '+', ' ')
    -- Decode %XX sequences
    input = string.gsub(input, '%%(%x%x)', urldecodehex)
    return input
end

function string.endswith(str, endStr)
    if not str or not endStr then
        return false
    end
    local len1 = string.len(str)
    local len2 = string.len(endStr)
    if len1 <= len2 then
        return str == endStr
    end
    return (string.sub(str, len1 - len2 + 1) == endStr)
end

function string.startswith(str, startStr)
    if not str or not startStr then
        return false
    end
    local len1 = string.len(str)
    local len2 = string.len(startStr)
    if len1 <= len2 then
        return str == startStr
    end
    return (string.sub(str, 1, len2) == startStr)
end


local _genReplaceArgs = function(param1, param2, param3, param4, param5, param6, ...)
    if type(param1) == "table" then
        return param1
    end
    local args = {}
    if not param1 then return args end
    args["a1"] = param1
    if not param2 then return args end
    args["a2"] = param2
    if not param3 then return args end
    args["a3"] = param3
    if not param4 then return args end
    args["a4"] = param4
    if not param5 then return args end
    args["a5"] = param5
    if not param6 then return args end
    args["a6"] = param6
    local tmp = {...}
    if #tmp > 0 then
        for k,v in ipairs(tmp) do
            local key = "a"..(k+6)
            args[key] = v
        end
    end
    return args
end

--- param1 是一个 table时 ，格式 {a1=replace1, a2=replace2 , ...}
--- param1 是一个字符串，那么，将会把它和后面的参数当成需要替换的值，按照顺序进行替换
---@param str string @ 源字符串
function string.replace(str, param1, param2, param3, param4, param5, param6, ...)
    --if string.find(str, "%%s") then
    --	return string.format(str, param1, param2, param3, param4, param5, param6, ...)
    --end
    local args = _genReplaceArgs(param1, param2, param3, param4, param5, param6, ...)
    local retStr, _num = string.gsub(str, "#(%w+)#", args)
    return retStr
end